+      const senderName = room.getMember(senderId)?.name ?? senderId;
+      const storeAllowFrom = await readChannelAllowFromStore("matrix").catch(() => []);
+      const effectiveAllowFrom = normalizeAllowListLower([...allowFrom, ...storeAllowFrom]);
