+      if (isRoom && roomConfigInfo.config?.users?.length) {
+        const userAllowed = resolveMatrixAllowListMatches({
+          allowList: normalizeAllowListLower(roomConfigInfo.config.users),
+          userId: senderId,
+          userName: senderName,
+        });
+        if (!userAllowed) {
